mapper.select:
select , c.name AS customerName, p.nickname AS petNickname, si.name AS serviceItemName, e.name AS empName from `order` o left join customer c on o.customer_id = c.id left join pet p on o.pet_id = p.id left join service_item si on o.service_item_id = si.id left join emp e on o.emp_id = e.id
and o.order_no = #{orderNo}
and c.name like concat('%', #{customerName}, '%')
and p.nickname like concat('%', #{petNickname}, '%')
and o.status = #{status}
and o.service_time >= #{serviceTimeBegin}
and o.service_time <= #{serviceTimeEnd}
order by o.create_time desc

mapper.update:
update `order`
set status = 4,
    cancel_reason = #{cancelReason}
where id = #{id}

mapper.select:
select , c.name AS customerName, p.nickname AS petNickname, si.name AS serviceItemName, e.name AS empName from `order` o left join customer c on o.customer_id = c.id left join pet p on o.pet_id = p.id left join service_item si on o.service_item_id = si.id left join emp e on o.emp_id = e.id
o.user_account_id = #{userAccountId}
and o.order_no = #{orderNo}
and o.status = #{status}
and o.service_time >= #{serviceTimeBegin}
and o.service_time <= #{serviceTimeEnd}
order by o.create_time desc

select

from `order` o
where o.id = #{id}
  and o.user_account_id = #{userAccountId}

select count(1)
from `order` o
where o.emp_id = #{empId}
  and o.status != 4
  and o.service_time < #{rangeEnd}
  and date_add(o.service_time, interval o.duration_minutes minute) > #{rangeStart}

    and o.id != #{excludeOrderId}
